def classify_star(spectral_class, luminosity_class):
    if luminosity_class == 'V':
        if spectral_class in ['M', 'K']:
            return 'Red dwarf'
        elif spectral_class == 'G':
            return 'Yellow dwarf'
        elif spectral_class in ['A', 'B']:
            return 'Blue dwarf'
    elif luminosity_class == 'D':
        return 'White dwarf'
    else:
        return 'Unknown type'

# Example usage:
print(classify_star('M', 'V'))  # Output: Red dwarf
print(classify_star('G', 'V'))  # Output: Yellow dwarf
print(classify_star('A', 'V'))  # Output: Blue dwarf
print(classify_star('M', 'D'))  # Output: White dwarf
